function getLangCodeForVoiceId(voiceId) {
  if (voiceId.startsWith("English_")) return "EN";
  if (voiceId.startsWith("Chinese (Mandarin)_")) return "ZH";
  if (voiceId === "Arrogant_Miss" || voiceId === "Robot_Armor") return "ZH";
  if (voiceId.startsWith("Japanese_")) return "JA";
  if (voiceId.startsWith("Cantonese_")) return "YUE";
  if (voiceId.startsWith("Korean_")) return "KO";
  if (voiceId.startsWith("Spanish_")) return "ES";
  if (voiceId.startsWith("Portuguese_")) return "PT";
  if (voiceId.startsWith("French_")) return "FR";
  if (voiceId.startsWith("Indonesian_")) return "ID";
  if (voiceId.startsWith("German_")) return "DE";
  if (voiceId.startsWith("Russian_")) return "RU";
  if (voiceId.startsWith("Italian_")) return "IT";
  if (voiceId.startsWith("Dutch_")) return "NL";
  if (voiceId.startsWith("Vietnamese_")) return "VI";
  if (voiceId.startsWith("Arabic_")) return "AR";
  if (voiceId.startsWith("Turkish_")) return "TR";
  if (voiceId.startsWith("Ukrainian_")) return "UK";
  if (voiceId.startsWith("Thai_")) return "TH";
  if (voiceId.startsWith("Polish_")) return "PL";
  if (voiceId.startsWith("Romanian_")) return "RO";
  if (voiceId.startsWith("greek_") || voiceId.startsWith("Greek_")) return "EL";
  if (voiceId.startsWith("czech_") || voiceId.startsWith("Czech_")) return "CS";
  if (voiceId.startsWith("finnish_")) return "FI";
  if (voiceId.startsWith("hindi_")) return "HI";
  return "";
}
